CREATE OR REPLACE FUNCTION fpa_fin_valid_bank_fin ( as_account_id char) RETURNS varchar AS $body$
DECLARE

  ls_bank_fin sc_fin_m_bank.bank_fin%type;

BEGIN

  select  bank_fin into STRICT ls_bank_fin
  from    sc_fin_m_bank
  where (account_id = as_account_id ) 
;
  return ls_bank_fin;

exception
  when no_data_found then
    return ' ';
  when others then
    RAISE EXCEPTION '%', 'FPA_FIN_VALID_BANK_FIN>'||trim(both sqlerrm) USING ERRCODE = '45000';
    return ' ';

end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
